import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'

import userLoginSucces from './userLoginSlice';


export const userRegisterSlice = createSlice({
    name: 'userRegister',
    initialState: {},
    reducers: {
        userRegisterRequest: (state, action) => {
            state.loading = true;
        },

        userRegisterSucces: (state, action) => { 
            state.loading = false;
            state.userInfo = action.payload; 
        },

        userRegisterFail: (state, action) => { 
           state.loading = false; 
            state.error = action.payload;
        },

        userLogout: (state) => {
            Object.assign(state, {})
        }
    }
})
export const { userRegisterRequest, userRegisterSucces, userRegisterFail, userLogout } = userRegisterSlice.actions
export default userRegisterSlice.reducer;


// thunk functions to login a user

export const register = (first_name='', last_name='', email, password) => async (dispatch) => {
    try{
        dispatch(userRegisterRequest())

        console.log("fname:", first_name)
        console.log('email:', email)
        console.log('type of fname:', typeof(first_name))

        const headers = {
            'Content-Type': 'application/json'
        }

        const { data } = await axios.post(
            'api/users/register/',
            { 'email': email,  'password':password },
            { headers: headers }
            )

        console.log(data)

        dispatch(userRegisterSucces(data))

        localStorage.setItem('userInfo', JSON.stringify(data))

        

        // after the user register, log the user in
        dispatch(userLoginSucces(data))

        
        
    } catch (error) {
        const msg = (error.response && error.response.data.message ? error.response.data.message : error.message)
        dispatch(userRegisterFail(msg))
    }
}

export const logout = () => (dispatch) => {
    localStorage.removeItem('userInfo')
    dispatch(userLogout())
}
